from flask import Flask, request, jsonify
from pymongo import MongoClient

app = Flask(__name__)

# Connect to MongoDB
client = MongoClient('mongodb://localhost:27017/')
db = client['cms']
users_collection = db['users']
documents_collection = db['documents']

@app.route('/user', methods=['POST'])
def create_user():
    user_data = request.json
    users_collection.insert_one(user_data)
    return jsonify({'message': 'User created successfully'}), 201

@app.route('/document', methods=['GET'])
def get_documents():
    query = {}
    if 'title' in request.args:
        query['title'] = {'$regex': request.args.get('title'), '$options': 'i'}
    documents = list(documents_collection.find(query))
    return jsonify({'documents': documents})

@app.route('/document', methods=['GET'])
def get_document():
    document_id = request.args.get('id')
    document = documents_collection.find_one({'_id': document_id})
    if document:
        return jsonify({'document': document})
    else:
        return jsonify({'message': 'Document not found'}), 404

@app.route('/aggregation', methods=['GET'])
def aggregation():
    pipeline = [
        {'$match': {'title': {'$regex': request.args.get('title'), '$options': 'i'}}},
        {'$group': {'_id': None, 'count': {'$sum': 1}}}
    ]
    result = list(documents_collection.aggregate(pipeline))
    return jsonify({'result': result})

if __name__ == '__main__':
    app.run(debug=True)